pub fn parse_endpoint(input: &str) -> Result<(String, u16), ()> {
    let trimmed = input.trim();
    let (host, port) = trimmed.split_once(':').ok_or(())?;
    let host = host.trim();
    if host.is_empty() {
        return Err(());
    }
    let port = port.parse::<u16>().map_err(|_| ())?;
    Ok((host.to_string(), port))
}
